const subscriptions={};let uid=0;const subscribe=(s,i)=>{s in subscriptions||(subscriptions[s]={});var n="pubsub_subscription_"+uid++;return subscriptions[s][n]=i,n},unsubscribe=(s,i)=>{delete subscriptions[s][i]},publish=(s,i)=>{for(const n in subscriptions)if(n===s||s.startsWith(n+"."))for(const t in subscriptions[n])subscriptions[n][t](s,i)},publishAsync=async(s,i)=>{const n=[];for(const t in subscriptions)if(t===s||s.startsWith(t+"."))for(const u in subscriptions[t])n.push(subscriptions[s][u](s,i));await Promise.all(n)};export{subscribe,unsubscribe,publish,publishAsync};